//! App-side part-mesh catalog + loader (WI 653): map a mechanical-kit part to its shipped glb and
//! spawn it at a mount, oriented/scaled per the catalog frame (+Y up, +Z forward, +X axle; reference
//! cell 0.5 m). The catalog table also feeds the gallery inspector. App-side only — the headless
//! crate has no notion of meshes.
//!
//! glb assets live under `assets/models/parts/<name>.glb`, generated by the asset-harness
//! `mechanical-kit` track (parametric Blender geometry + AI PBR surfaces). A part identity with no
//! shipped glb falls back to a caller-supplied placeholder via [`part_glb_path`] returning `None`.

use bevy::gltf::GltfAssetLabel;
use bevy::prelude::*;
use sounding_sim::voxel::{device_mass, DeviceKind, PartKind};

/// The reference cell the parts were authored at (manifest `reference_cell`); a part is scaled by
/// `cell_size / REFERENCE_CELL` so it matches the build's cell size.
pub const REFERENCE_CELL: f64 = 0.5;

/// Catalog grouping for the gallery layout.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum PartCategory {
    Drivetrain,
    Power,
    Cockpit,
    Structure,
    Comms,
    Rocket,
    Fitting,
}

impl PartCategory {
    pub fn label(self) -> &'static str {
        match self {
            PartCategory::Drivetrain => "Drivetrain",
            PartCategory::Power => "Power",
            PartCategory::Cockpit => "Cockpit",
            PartCategory::Structure => "Structure",
            PartCategory::Comms => "Comms",
            PartCategory::Rocket => "Rocket",
            PartCategory::Fitting => "Fittings",
        }
    }

    /// Layout/row order in the gallery.
    pub const ORDER: [PartCategory; 7] = [
        PartCategory::Drivetrain,
        PartCategory::Power,
        PartCategory::Cockpit,
        PartCategory::Structure,
        PartCategory::Comms,
        PartCategory::Rocket,
        PartCategory::Fitting,
    ];
}

/// A catalog entry: the glb basename plus the metadata the gallery inspector shows. `device` ties a
/// part to a `DeviceKind` so device-backed parts (motor/battery/tank/…) can report a mass.
pub struct CatalogPart {
    pub name: &'static str,
    pub category: PartCategory,
    pub material_set: &'static str,
    pub orientation: &'static str,
    pub verts: u32,
    pub device: Option<DeviceKind>,
}

