/// The catalog entry for `name`, if any.
pub fn catalog_part(name: &str) -> Option<&'static CatalogPart> {
    CATALOG.iter().find(|p| p.name == name)
}

/// The asset path for a part glb, or `None` if the part is not in the catalog (the caller should then
/// fall back to a placeholder mesh rather than bind a missing path).
pub fn part_glb_path(name: &str) -> Option<String> {
    catalog_part(name).map(|p| format!("models/parts/{}.glb", p.name))
}

/// The glb basename a `DeviceKind` renders as (the retrofit mapping), or `None` (→ placeholder).
pub fn device_part_name(kind: DeviceKind) -> Option<&'static str> {
    Some(match kind {
        DeviceKind::Engine => "motor",
        DeviceKind::Tank => "fuel_tank",
        DeviceKind::Battery => "battery",
        DeviceKind::Computer => "tablet",
        DeviceKind::Command => "seat",
        DeviceKind::Rcs => return None,
    })
}

/// The glb basename a `PartKind` renders as (the workshop retrofit mapping). Every kind maps to a
/// catalogued part; the legacy monolithic `Wheel` shows as a `tire`.
pub fn part_kind_name(kind: PartKind) -> &'static str {
    match kind {
        PartKind::Wheel(_) => "tire",
        PartKind::Suspension(_) => "suspension",
        PartKind::Rim(_) => "rim",
        PartKind::Tire(_) => "tire",
        PartKind::Seat => "seat",
        PartKind::Antenna => "antenna",
        PartKind::SolarPanel => "solar_panel",
        PartKind::Bumper => "bumper",
    }
}

/// Spawn a part's glb `SceneRoot` at `translation`/`rotation`, scaled by `cell_size / REFERENCE_CELL`.
/// Returns the spawned root entity so the caller can attach markers. Assumes the part is in the
/// catalog (`part_glb_path` is `Some`); callers handle the placeholder case themselves.
pub fn spawn_part_mesh(
    commands: &mut Commands,
    asset_server: &AssetServer,
    name: &str,
    cell_size: f64,
    translation: Vec3,
    rotation: Quat,
) -> Entity {
    let path = part_glb_path(name).expect("spawn_part_mesh called for an uncatalogued part");
    let scene = asset_server.load(GltfAssetLabel::Scene(0).from_asset(path));
    let scale = (cell_size / REFERENCE_CELL) as f32;
    // The parts are authored +Y-up in Blender; the glTF exporter's Z-up→Y-up rotation lands their
    // "up" along -Z in glTF/Bevy space. Rotate +90° about X to bring it back to Bevy's +Y-up (and
    // forward to +Z, axle to +X) — the frame the manifest intends. Composed under the caller's
    // mount rotation so caller orientations still apply on top of the corrected part.
    let rotation = rotation * Quat::from_rotation_x(std::f32::consts::FRAC_PI_2);
    commands
        .spawn((
            SceneRoot(scene),
            Transform {
                translation,
                rotation,
                scale: Vec3::splat(scale),
            },
        ))
        .id()
}

/// The display mass (kg) of a device-backed part at `cell_size`, for the inspector.
pub fn part_device_mass(part: &CatalogPart, cell_size: f64) -> Option<f64> {
    part.device.map(|k| device_mass(k, cell_size))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn every_catalog_part_has_a_shipped_glb() {
        let root = std::path::Path::new(env!("CARGO_MANIFEST_DIR")).join("assets/models/parts");
        for p in CATALOG {
            let f = root.join(format!("{}.glb", p.name));
            assert!(f.exists(), "missing part glb: {}", f.display());
        }
    }

    #[test]
    fn every_device_kind_maps_to_a_catalogued_part_or_none() {
        for k in [
            DeviceKind::Command,
            DeviceKind::Engine,
            DeviceKind::Tank,
            DeviceKind::Rcs,
            DeviceKind::Computer,
            DeviceKind::Battery,
        ] {
            if let Some(name) = device_part_name(k) {
                assert!(catalog_part(name).is_some(), "{name} not in catalog for {k:?}");
            }
        }
    }

    #[test]
    fn catalog_covers_all_categories() {
        for c in PartCategory::ORDER {
            assert!(CATALOG.iter().any(|p| p.category == c), "no parts in {:?}", c);
        }
    }
}
